pc.script.createLoadingScreen(function(app) {
    var showSplash = function() {
        var logoSrc = 'data:image/jpeg;base64,';
        // splash wrapper
        var wrapper = document.createElement('div');
        wrapper.id = 'application-splash-wrapper';
        document.body.appendChild(wrapper);

        // splash
        var splash = document.createElement('div');
        splash.id = 'application-splash';
        wrapper.appendChild(splash);
        splash.style.display = 'none';

        var logo = document.createElement('img');
        logo.src = logoSrc;
        splash.appendChild(logo);
        logo.onload = function() {
            splash.style.display = 'block';
        };

        var container = document.createElement('div');
        container.id = 'progress-bar-container';
        splash.appendChild(container);

        var bar = document.createElement('div');
        bar.id = 'progress-bar';
        container.appendChild(bar);
        var application = pc.Application.getApplication();
        application.graphicsDevice.maxPixelRatio = Math.min(window.devicePixelRatio, 2);
        // console.log(application.graphicsDevice.maxPixelRatio)
    };

    var hideSplash = function() {
        var splash = document.getElementById('application-splash-wrapper');
        splash.parentElement.removeChild(splash);
    };

    var initGraphics = function() {
        pc.quality = {};

        // Trackbuilder related settings
        // NOTE: If enabling/disabling --> adjust preload settings on model!
        // NOTE: If enabling/disabling --> adjust visibility in editor
        pc.quality.skipAreaList = []; //['MOSCOW_PARK', 'MOSCOW_CROSSROAD'];
        pc.quality.preAllocateScene = true; // Prepares trackBuilder if true

        // Quality related settings
        pc.quality.viewDistance = 140.0; // viewDistance in world units (DONT CHANGE, this will require more memory)
        pc.quality.renderDistance = 135.0; // Makes sure areas are not spawning visibly at horizon
        pc.quality.frustumCulling = false; // Render objects not visible on camera
        pc.quality.multiSampling = 1; // amount of multisampling to apply to final texture
        pc.quality.fragPrecision = "highp"; // highp, lowp (WARNING!: mediump can cause glitches on mobile not visible on pc)
        //pc.quality.alphaWrite = true;               // Write to alpha channel
        pc.quality.blendType = pc.BLEND_NONE; // Set blendType between alpha values
        pc.quality.gammaType = pc.GAMMA_SRGBFAST; // pc.GAMMA_NONE, pc.GAMMA_SRGB
        pc.quality.useLighting = false; // Simple FORWARD render pass (tested: huge impact on performance)
        pc.quality.pixelSnapping = false; // Snap every fragment to an exact pixel
        pc.quality.useInstancing = true; // Try to use instancing on every material
        pc.quality.toneMapping = pc.TONEMAP_LINEAR; // pc.TONEMAP_FILMIC,pc.TONEMAP_HEJL,pc.TONEMAP_ACES
        //pc.quality.forceMaterial = true;            // Exclusively render materials defined in the object (ie. skips shadowplanes)

        // WorldBender related settings
        pc.quality.useBending = true; // Bend the world
        pc.quality.useAlphaTextures = true; // Allows transparent textures in worldbender
        pc.quality.useSkyBlending = true; // not implemented yet
        pc.quality.useDeviceRatio = true; // adjust warping to aspectRatio
        pc.quality.bendXamount = 6.8; // dx bend in worldUnits at horizon 6.2
        pc.quality.bendYamount = 5.2; // dy bend in worldUnits at horizon 4.8
        pc.quality.bendXscalar = 2.0; // scalar for applying bending algorithm
        pc.quality.bendYscalar = 2.2;
        pc.quality.alphaBias = 2.2; // how far away the blending starts ~ f(): 1.0 - (1/alphaBias)
        pc.quality.lightBias = 1.0; // fake lighting (brightness multiplier)*/

        // GraphicsDevice related settings
        pc.quality.device = app.graphicsDevice;
        pc.quality.device.enableAutoInstancing = !!pc.quality.device.extInstancing;
        pc.quality.device.setCullMode(pc.CULLFACE_BACK);
        pc.quality.device.setDepthFunc(pc.FUNC_LESSEQUAL);
        pc.quality.device.setDepthTest(true);
        pc.quality.device.setDepthWrite(true);
        pc.quality.device.setStencilTest(false);

        // nActiveTextures = pc.quality.device.textures.length
        // targetsamples = pc.quality.device.targets[i]._samples
        // samplerCount = pc.quality.device.samplerCount
        // nRenderTargets = pc.quality.device.targets.length
        // shaderVariables = pc.quality.device.scope.variables
        // onfocus:, onerror:, onclose: = pc.quality.device.gl.canvas
        // activeDrawCalls = pc.quality.device._drawCallsPerFrame

        // platform = navigator.platform
        // userAgent = navigator.userAgent
        // language = navigator.language
        // view-source:http://cdn.webglstats.com/stat.js --> check for software Renderer

        //console.log(pc.quality.device.unmaskedRenderer);

        if (pc.quality.device.maxVertexTextures < 4) console.warn("Loading: maxVertexTextures is low (" + pc.quality.device.maxVertexTextures + ")");
        if (pc.quality.device.maxTextureSize < 2048) console.warn("Loading: maxTextureSize is low (" + pc.quality.device.maxTextureSize + ")");
    };

    var setProgress = function(value) {
        var bar = document.getElementById('progress-bar');
        if (bar) {
            value = Math.min(1, Math.max(0, value));
            bar.style.width = value * 100 + '%';
        }
    };

    var createCss = function() {
        var css = [
            'body {',
            '    background-color: #000000;',
            '}',

            '#application-splash-wrapper {',
            '    position: absolute;',
            '    top: 0;',
            '    left: 0;',
            '    height: 100%;',
            '    width: 100%;',
            '    background-color: #000000;',
            '}',

            '#application-splash {',
            '    position: absolute;',
            '    top: calc(20% - 28px);',
            '    width: 264px;',
            '    left: calc(50% - 132px);',
            '}',

            '#application-splash img {',
            '    width: 100%;',
            '}',

            '#progress-bar-container {',
            '    margin: 20px auto 0 auto;',
            '    height: 2px;',
            '    width: 100%;',
            '    background-color: #1d292c;',
            '}',

            '#progress-bar {',
            '    width: 0%;',
            '    height: 100%;',
            '    background-color: #f60;',
            '}',
            '@media (max-width: 480px) {',
            '    #application-splash {',
            '        width: 170px;',
            '        left: calc(50% - 85px);',
            '    }',
            '}',

        ].join("\n");



        var style = document.createElement('style');
        style.type = 'text/css';
        if (style.styleSheet) {
            style.styleSheet.cssText = css;
        } else {
            style.appendChild(document.createTextNode(css));
        }

        document.head.appendChild(style);

        var div = document.createElement("div");
        div.innerHTML = '<div class="fontPreload1">.</div>';
        document.body.insertBefore(div, document.body.firstChild);
    };

    if (pc.gdsdkManager) {
        pc.gdsdkManager.preloadAd();
    }





    // This script fires the following events
    // on the pc.Application:
    // fb:instant:init  - Fired when the Facebook Instant SDK has been initialized
    // fb:instant:start - Fired when the player has hit Play in the Facebook Instant UI
    // fb:instant:reset - Fired when the player hit Play to restart the game in the Facebook Instant UI
    //
    // In order to set the score fire 'fb:instant:score' on the pc.Application passing the score as an argument.
    //setStyle();

    var canvas = document.createElement('canvas');

    createCss();

    showSplash();
    app.on('preload:progress', function(value) {
        setProgress(value);
        if(value>=0.99){
            window.adsGameCon.recordOpen();
        }
    });
    app.on('preload:end', function() {
        app.off('preload:progress');
    });

    app.on('start', initGraphics);
    app.on('start', function() {

        var application = pc.Application.getApplication();
        setTimeout(function() {
            application.fire('loadingScreen:activateText');
            if (!('FBInstant' in window)) {
                application.fire('loadingScreen:activateText');
                // pc.freeTicketManager.setData(undefined);
                application.fire("loadingscreen:addCanvas", canvas);

                application.fire('fb:instant:start');
            }

            application.fire('removeOverlay');
            hideSplash();

        }, 1000);
    });

});
window.gamePause = null;
window.gameStart = null;